import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../../api/api";

const AdminDashboard = () => {
  const user     = JSON.parse(localStorage.getItem("user") || "{}");
  const navigate = useNavigate();

  const [stats, setStats]     = useState({ users: 0, projects: 0, proposals: 0, freelancers: 0, clients: 0 });
  const [projects, setProjects] = useState([]);
  const [allUsers, setAllUsers] = useState([]);
  const [loading, setLoading]  = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const [statsRes, usersRes, projRes] = await Promise.all([
          API.get("/admin/dashboard"),
          API.get("/users/"),
          API.get("/projects/"),
        ]);
        const users = usersRes.data || [];
        setAllUsers(users);
        setStats({
          ...statsRes.data,
          freelancers: users.filter(u => u.role === "freelancer").length,
          clients:     users.filter(u => u.role === "client").length,
        });
        setProjects(projRes.data || []);
      } catch (err) { console.error(err); }
      setLoading(false);
    };
    load();
  }, []);

  // ✅ Generate Full PDF Report using jsPDF (CDN)
  const generatePDF = (todayOnly = false) => {
    // Dynamically load jsPDF from CDN
    if (!window.jspdf) {
      const script = document.createElement("script");
      script.src = "https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js";
      script.onload = () => buildPDF(todayOnly);
      document.head.appendChild(script);
    } else {
      buildPDF(todayOnly);
    }
  };

  const buildPDF = (todayOnly) => {
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF();

    const today = new Date().toLocaleDateString("en-IN", {
      day: "2-digit", month: "long", year: "numeric"
    });
    const now = new Date().toLocaleTimeString("en-IN");

    // ── HEADER ──
    doc.setFillColor(15, 118, 110); // teal
    doc.rect(0, 0, 210, 28, "F");
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(18);
    doc.setFont("helvetica", "bold");
    doc.text("FreelanceHub", 14, 12);
    doc.setFontSize(11);
    doc.setFont("helvetica", "normal");
    doc.text(todayOnly ? "Today's Login Report" : "Full Platform Report", 14, 20);
    doc.text(`Generated: ${today} ${now}`, 210 - 14, 20, { align: "right" });

    doc.setTextColor(0, 0, 0);
    let y = 38;

    if (!todayOnly) {
      // ── PLATFORM STATS ──
      doc.setFontSize(13);
      doc.setFont("helvetica", "bold");
      doc.text("Platform Statistics", 14, y);
      y += 8;

      doc.setFontSize(10);
      doc.setFont("helvetica", "normal");
      const statsData = [
        ["Total Users", stats.users],
        ["Freelancers", stats.freelancers],
        ["Clients",     stats.clients],
        ["Total Projects",  stats.projects],
        ["Total Proposals", stats.proposals],
      ];
      statsData.forEach(([label, val]) => {
        doc.setFillColor(240, 253, 250);
        doc.rect(14, y - 4, 80, 8, "F");
        doc.text(label, 16, y);
        doc.setFont("helvetica", "bold");
        doc.text(String(val), 90, y);
        doc.setFont("helvetica", "normal");
        y += 10;
      });

      y += 5;

      // ── PROJECT DETAILS ──
      doc.setFontSize(13);
      doc.setFont("helvetica", "bold");
      doc.text("Project Details", 14, y);
      y += 8;

      // Table header
      doc.setFillColor(15, 118, 110);
      doc.rect(14, y - 5, 182, 8, "F");
      doc.setTextColor(255, 255, 255);
      doc.setFontSize(9);
      doc.text("Title",  16, y);
      doc.text("Status", 90, y);
      doc.text("Budget", 130, y);
      doc.text("Client", 165, y);
      y += 6;
      doc.setTextColor(0, 0, 0);
      doc.setFont("helvetica", "normal");

      projects.forEach((p, i) => {
        if (y > 270) { doc.addPage(); y = 20; }
        if (i % 2 === 0) {
          doc.setFillColor(248, 250, 252);
          doc.rect(14, y - 4, 182, 8, "F");
        }
        doc.text((p.title || "").slice(0, 35), 16, y);
        doc.text(p.status || "open", 90, y);
        doc.text(`Rs.${p.budget}`, 130, y);
        doc.text(p.client_name || "-", 165, y);
        y += 9;
      });

      y += 8;

      // ── USER LIST ──
      doc.setFontSize(13);
      doc.setFont("helvetica", "bold");
      doc.text("Registered Users", 14, y);
      y += 8;

      doc.setFillColor(15, 118, 110);
      doc.rect(14, y - 5, 182, 8, "F");
      doc.setTextColor(255, 255, 255);
      doc.setFontSize(9);
      doc.text("Name",  16, y);
      doc.text("Email", 70, y);
      doc.text("Role",  165, y);
      y += 6;
      doc.setTextColor(0, 0, 0);
      doc.setFont("helvetica", "normal");

      allUsers.filter(u => u.role !== "admin").forEach((u, i) => {
        if (y > 270) { doc.addPage(); y = 20; }
        if (i % 2 === 0) {
          doc.setFillColor(248, 250, 252);
          doc.rect(14, y - 4, 182, 8, "F");
        }
        doc.text((u.name || "").slice(0, 30), 16, y);
        doc.text((u.email || "").slice(0, 40), 70, y);
        doc.text(u.role || "-", 165, y);
        y += 9;
      });

    } else {
      // ── TODAY'S LOGIN REPORT ──
      const todayStr = new Date().toDateString();
      doc.setFontSize(13);
      doc.setFont("helvetica", "bold");
      doc.text(`Today's Users — ${today}`, 14, y);
      y += 8;

      const todayUsers = allUsers; // In real app, filter by login date
      doc.setFillColor(15, 118, 110);
      doc.rect(14, y - 5, 182, 8, "F");
      doc.setTextColor(255, 255, 255);
      doc.setFontSize(9);
      doc.text("Name",  16, y);
      doc.text("Email", 70, y);
      doc.text("Role",  165, y);
      y += 6;
      doc.setTextColor(0, 0, 0);
      doc.setFont("helvetica", "normal");

      todayUsers.forEach((u, i) => {
        if (y > 270) { doc.addPage(); y = 20; }
        if (i % 2 === 0) {
          doc.setFillColor(248, 250, 252);
          doc.rect(14, y - 4, 182, 8, "F");
        }
        doc.text((u.name || "").slice(0, 30), 16, y);
        doc.text((u.email || "").slice(0, 40), 70, y);
        doc.text(u.role || "-", 165, y);
        y += 9;
      });
    }

    // ── FOOTER ──
    const pageCount = doc.internal.getNumberOfPages();
    for (let i = 1; i <= pageCount; i++) {
      doc.setPage(i);
      doc.setFontSize(8);
      doc.setTextColor(150);
      doc.text(`FreelanceHub — Confidential  |  Page ${i} of ${pageCount}`, 14, 290);
    }

    doc.save(todayOnly ? `login-report-${today}.pdf` : `freelancehub-report-${today}.pdf`);
  };

  if (loading) return <div className="text-center py-16 text-gray-400">Loading...</div>;

  return (
    <div className="bg-white min-h-screen p-8">
      <div className="max-w-5xl mx-auto">

        {/* HEADER */}
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-3xl font-bold text-gray-800">Admin Dashboard</h1>
        </div>

        {/* STAT CARDS — like image 1 */}
        <div className="grid grid-cols-3 gap-6 mb-8">
          {[
            { label: "Clients",     value: stats.clients,     color: "text-blue-600" },
            { label: "Freelancers", value: stats.freelancers, color: "text-green-600" },
            { label: "Projects",    value: stats.projects,    color: "text-purple-600" },
          ].map((s, i) => (
            <div key={i} className="bg-white border border-gray-200 rounded-xl p-6 text-center shadow-sm">
              <p className={`text-4xl font-bold ${s.color}`}>{s.value}</p>
              <p className="text-gray-500 mt-2">{s.label}</p>
            </div>
          ))}
        </div>

        {/* PROJECT DETAILS TABLE */}
        <div className="bg-white border border-gray-200 rounded-xl shadow-sm mb-6">
          <div className="p-5 border-b border-gray-100">
            <h2 className="text-lg font-bold text-gray-700">Project Details</h2>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead className="bg-gray-50 border-b border-gray-100">
                <tr>
                  <th className="text-left px-5 py-3 text-gray-500 font-medium">Title</th>
                  <th className="text-left px-5 py-3 text-gray-500 font-medium">Status</th>
                  <th className="text-left px-5 py-3 text-gray-500 font-medium">Budget</th>
                  <th className="text-left px-5 py-3 text-gray-500 font-medium">Client</th>
                  <th className="text-left px-5 py-3 text-gray-500 font-medium">Proposals</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {projects.length === 0 ? (
                  <tr><td colSpan={5} className="text-center py-8 text-gray-400">No projects yet.</td></tr>
                ) : projects.map((p, i) => (
                  <tr key={i} className="hover:bg-gray-50 transition">
                    <td className="px-5 py-3 font-medium text-gray-800">{p.title}</td>
                    <td className="px-5 py-3">
                      <span className={`px-2 py-0.5 rounded-full text-xs font-semibold capitalize ${
                        p.status === "closed" ? "bg-red-100 text-red-600" : "bg-green-100 text-green-600"
                      }`}>{p.status || "Open"}</span>
                    </td>
                    <td className="px-5 py-3 text-gray-600">₹{p.budget}</td>
                    <td className="px-5 py-3 text-gray-600">{p.client_name || "—"}</td>
                    <td className="px-5 py-3 text-gray-600">{p.proposals_count || 0}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* PDF BUTTONS — like image 1 */}
          <div className="p-5 border-t border-gray-100 flex gap-3">
            <button
              onClick={() => generatePDF(false)}
              className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2 rounded-lg text-sm font-medium transition">
              📄 Generate Full PDF Report
            </button>
            <button
              onClick={() => generatePDF(true)}
              className="flex items-center gap-2 bg-green-600 hover:bg-green-700 text-white px-5 py-2 rounded-lg text-sm font-medium transition">
              📊 Generate Today's Login Report
            </button>
          </div>
        </div>

      </div>
    </div>
  );
};

export default AdminDashboard;
